#!/bin/bash

# This script processses the XML tests results and outputs a NDJSON stream with one document per test execution.
# Hence, each document corresponds to a testcase entry in the XML. It contains the following fields:
#
#   - 'suite_name': As the entry class name.
#   - 'test': As the entry name.
#   - 'result': success/failure/pass from the optional child node of the entry. No child node means success.
#   - 'timestamp': As the testsuite (parent of the entry) timestamp field.
#   - 'duration_s': As the time field of the entry.
#   - 'reason': As the entry child (pass or failure) contents. For example, in the source, <failure>SOURCE FOR REASON</failure>.
#   - 'workflow_run_id': As the content of the environment variable 'WORKFLOW_RUN_ID'
#   - 'workflow_run_link': As the content of the environment variable 'WORKFLOW_RUN_LINK'
#   - 'workflow_retry_number': As the content of the environment variable 'WORKFLOW_RUN_NUMBER'
#   - 'workflow_head_branch': As the content of the environment variable 'WORKFLOW_HEAD_BRANCH'
#
# INPUT: The XML file(s) to process. For example, the test results generated by JUnit in the 'target/surefire-reports' directory.
# OUTPUT: NDJSON stream through stdout.
#
yq -p=xml -o=json \
  '
  .testsuites.testsuite[] |
  ."+@timestamp" as $ts |
  select(has("testcase")) |
  ((.testcase | select(kind == "seq") | .[]), (.testcase | select(kind == "map"))) |
  {
    "suite_name": ."+@classname",
    "test": ."+@name",
    "result": ((keys | map(select(. == "failure" or . == "skipped")) | .[0]) // "success"),
    "timestamp": $ts,
    "duration_s": (."+@time" | select(. != "") | tonumber // null),
    "reason": ((.failure."+content" // .skipped."+@message") // null),
    "workflow_run_id": ((strenv(WORKFLOW_RUN_ID) | select(. != "") | tonumber) // null),
    "workflow_run_link": ((strenv(WORKFLOW_RUN_LINK) | select(. != "")) // null),
    "workflow_retry_number": ((strenv(WORKFLOW_RUN_NUMBER) | select(. != "") | tonumber) // null),
    "workflow_head_branch": ((strenv(WORKFLOW_HEAD_BRANCH) | select(. != "")) // null)
  } |
  select(.suite_name != null)
  ' \
  "$@";